// Calculate indicators and absolute score
let data = msg.payload.rows[0]; // Assume single row

// Indicator calculations (score -1 to 1)
let nq_vs_200ma = data.price > data.ma200 ? 1 : -1;
let nq_vs_50ma = data.price > data.ma50 ? 1 : -1;
let ema20_vs_50 = data.ema20 > data.ema50 ? 1 : -1;
let mtf_trend = data.mtf_trend === 'bullish' ? 1 : -1; // Assume mtf_trend is string
let market_phase = data.market_phase === 'bull' ? 1 : -1; // Assume market_phase is string

// Weighted sum
let absolute_score = (nq_vs_200ma * 0.3) + (nq_vs_50ma * 0.3) + (ema20_vs_50 * 0.2) + (mtf_trend * 0.1) + (market_phase * 0.1);

// Normalize to 0-100
absolute_score = (absolute_score + 1) * 50; // From -1 to 1 -> 0 to 100

msg.payload = {
  date: data.date,
  absolute_score: absolute_score
};

return msg;
